const body = ($input.item.json && $input.item.json.body) || $input.item.json || {};
const secret = body.internal_secret || '';
const expected = process.env.INTERNAL_EMAIL_SECRET || '';
if (!expected || secret !== expected) return { json: { _unauthorized: true, error: 'internal secret required' } };
if (!body.suitability_assessment_id) return { json: { _empty: true, error: 'suitability_assessment_id required' } };
return { json: { _authorized: true, suitability_assessment_id: body.suitability_assessment_id } };

// PHASE 5 MVP — static carrier product matrix.
// Phase 6 swaps this for live carrier-API integration (Manulife/Sun Life/Canada Life/iA/RBC/etc.).
// Premium values are illustrative ranges; real quoting requires carrier APIs + medical underwriting.
const rows = $input.item.json;
const a = (Array.isArray(rows) ? rows[0] : rows) || null;
if (!a || !a.id) return { json: { _not_found: true } };

const products = {
  term_life: [
    { carrier: 'Manulife',     product: 'Family Term',          features: { renewable: true, convertible: true, child_rider_available: true } },
    { carrier: 'Sun Life',     product: 'SunTerm',              features: { renewable: true, convertible: true, child_rider_available: true } },
    { carrier: 'Canada Life',  product: 'My Term',              features: { renewable: true, convertible: true, child_rider_available: true } },
    { carrier: 'iA Financial', product: 'Term Life Pick-A-Term',features: { renewable: true, convertible: true, child_rider_available: false } },
    { carrier: 'RBC Insurance',product: 'YourTerm',             features: { renewable: true, convertible: true, child_rider_available: true } }
  ],
  whole_life: [
    { carrier: 'Manulife',     product: 'Manulife Par',         features: { participating: true, vanishing_premium: true } },
    { carrier: 'Sun Life',     product: 'Sun Par Protector II', features: { participating: true, vanishing_premium: true } },
    { carrier: 'Canada Life',  product: 'Wealth Achiever Plus', features: { participating: true, vanishing_premium: true } }
  ],
  critical_illness: [
    { carrier: 'Manulife',     product: 'Lifecheque',           features: { return_of_premium: true, conditions_covered: 25 } },
    { carrier: 'Sun Life',     product: 'Sun CII',              features: { return_of_premium: true, conditions_covered: 25 } },
    { carrier: 'Canada Life',  product: 'LifeAdvance CI',       features: { return_of_premium: true, conditions_covered: 26 } }
  ],
  disability: [
    { carrier: 'Manulife',     product: 'Venture Series',       features: { professional_class: true, own_occupation: true } },
    { carrier: 'RBC Insurance',product: 'Quantum',              features: { professional_class: true, own_occupation: true } },
    { carrier: 'Canada Life',  product: 'Lifestyle Protector',  features: { professional_class: true, own_occupation: true } }
  ],
  auto: [
    { carrier: 'Intact',       product: 'Personal Auto',        features: { multi_vehicle_discount: true } },
    { carrier: 'Aviva',        product: 'Aviva Auto',           features: { multi_vehicle_discount: true } },
    { carrier: 'Wawanesa',     product: 'Wawanesa Auto',        features: { loyalty_discount: true } }
  ],
  home: [
    { carrier: 'Intact',       product: 'Homeowners',           features: { water_endorsement: true, sewer_backup: true } },
    { carrier: 'Aviva',        product: 'Ovation Home',         features: { water_endorsement: true, sewer_backup: true } },
    { carrier: 'Economical',   product: 'Vyne Home',            features: { water_endorsement: true, sewer_backup: true } }
  ],
  commercial: [
    { carrier: 'Northbridge',  product: 'Commercial Package',   features: { cyber_endorsement: true, e_and_o_addon: true } },
    { carrier: 'Aviva',        product: 'Enterprise',           features: { cyber_endorsement: true, e_and_o_addon: true } },
    { carrier: 'Intact',       product: 'Business Choice',      features: { cyber_endorsement: true } }
  ]
};

const available = products[a.product_type] || [];

const systemPrompt = [
  'You are the Crystallux AI Policy Recommendation Engine for the INSURANCE vertical (vertical_id=insurance).',
  'Product type: ' + a.product_type,
  'Rank top 3-5 products by match quality given the client needs.',
  '',
  'For EACH product output:',
  '{',
  '  "carrier_name":     <string from available list>,',
  '  "product_name":     <string from available list>,',
  '  "coverage_amount_cents":   <integer>,',
  '  "premium_monthly_cents":   <integer>,',
  '  "premium_annual_cents":    <integer>,',
  '  "term_years":              <integer, 0 if not term-based>,',
  '  "ai_match_score":          <integer 0-100>,',
  '  "ai_ranking":              <integer 1-N, 1=best>,',
  '  "ai_reasoning":            <2-3 sentences>',
  '}',
  '',
  'Output strictly JSON: { "recommendations": [ ... ] }',
  '',
  'Rules:',
  '- Premium estimates are PRELIMINARY (real quoting requires carrier APIs + underwriting). Mark all premiums as illustrative ranges in your reasoning.',
  '- Use only carriers from the available list.',
  '- Consider: client needs (coverage gap), affordability (income vs premium), carrier reputation, product features.',
  '- For term_life: term_years should match recommended_term_years from needs_analysis.',
  '- coverage_amount_cents must match needs_analysis.recommended_coverage_cents UNLESS you are recommending a step-down for affordability — call that out.'
].join('\n');

const userPayload = JSON.stringify({
  vertical_id: 'insurance',
  product_type: a.product_type,
  needs_analysis: a.needs_analysis,
  ai_recommended_coverage_amount_cents: a.ai_recommended_coverage_amount,
  ai_recommended_term_years: a.ai_recommended_term_years,
  client_situation: a.client_situation,
  available_products: available
});

return { json: {
  assessment: a,
  available_count: available.length,
  claude_payload: {
    model: 'claude-sonnet-4-5-20250929',
    max_tokens: 1500,
    temperature: 0.2,
    system: systemPrompt,
    messages: [ { role: 'user', content: userPayload } ]
  }
} };

const a = $('Build Claude Prompt').item.json.assessment;
const resp = $input.item.json || {};
let text = '';
try { text = (resp.content && resp.content[0] && resp.content[0].text) || ''; } catch (e) {}
let parsed = null;
try { parsed = JSON.parse(String(text).replace(/```json|```/g, '').trim()); } catch (e) {}
const recs = (parsed && Array.isArray(parsed.recommendations)) ? parsed.recommendations : [];
const tokens = (resp.usage && (resp.usage.input_tokens + resp.usage.output_tokens)) || 0;

if (recs.length === 0) {
  return [{ json: { _no_recs: true, suitability_assessment_id: a.id, client_id: a.client_id, advisor_id: a.advisor_id, tokens: tokens } }];
}

return recs.map(function (r, idx) {
  return { json: {
    insert_row: {
      vertical_id: 'insurance',
      suitability_assessment_id: a.id,
      carrier_name: r.carrier_name,
      product_name: r.product_name,
      product_type: a.product_type,
      coverage_amount: parseInt(r.coverage_amount_cents) || 0,
      premium_monthly: parseInt(r.premium_monthly_cents) || 0,
      premium_annual: parseInt(r.premium_annual_cents) || 0,
      term_years: parseInt(r.term_years) || 0,
      features: {},
      ai_match_score: Math.min(Math.max(parseInt(r.ai_match_score) || 0, 0), 100),
      ai_ranking: parseInt(r.ai_ranking) || (idx + 1),
      ai_reasoning: r.ai_reasoning || null,
      status: 'recommended'
    },
    suitability_assessment_id: a.id,
    client_id: a.client_id,
    advisor_id: a.advisor_id,
    tokens: idx === 0 ? tokens : 0
  } };
});
